 80	export const loader = routeHandler(function* () {
 81	  const { request } = yield* ReactRouterContext;
 82	  const auth = yield* Auth.Service;
 83	  // 404 the whole area when disabled; the layout guard already redirected an
 84	  // unauthenticated visitor, but re-checking keeps this route safe on its own.
 85	  yield* auth.checkCookie(request.headers.get('cookie')).pipe(
 86	    Effect.catchTags({
 87	      'Auth.Disabled': () =>
 88	        Effect.fail(new Response('Not Found', { status: 404 })),
 89	      'Auth.Unauthorized': () => Effect.fail(redirect('/admin/login')),
 90	    }),
 91	  );
 92	
 93	  const editor = yield* DraftEditor.Service;
 94	  const env = yield* Env.Service;
 95	  const { content: document, source } = yield* editor.load(siteScope);
 96	  const encoded = yield* encodeDocument(document);
 97	
 98	  // The bucket is "configured" exactly when `Env.bucket` is present — the single
 99	  // source of truth (a bucket-less editor still renders so the admin can preview,
100	  // but saving/publishing would fail, which we warn about up front).
101	  const bucketConfigured = Option.isSome(env.bucket);
102	
103	  return { document: encoded as EncodedDocument, source, bucketConfigured };
104	});
