106	export const action = routeAction(function* () {
107	  const { request } = yield* ReactRouterContext;
108	  const auth = yield* Auth.Service;
109	  yield* auth.checkCookie(request.headers.get('cookie')).pipe(
110	    Effect.catchTags({
111	      'Auth.Disabled': () =>
112	        Effect.fail(new Response('Not Found', { status: 404 })),
113	      'Auth.Unauthorized': () => Effect.fail(redirect('/admin/login')),
114	    }),
115	  );
116	
117	  const editor = yield* DraftEditor.Service;
118	  const storage = yield* Storage.Service;
119	  const form = yield* Effect.promise(() => request.formData());
120	  const intent = String(form.get('intent') ?? 'save-draft');
121	
122	  // ---- image upload --------------------------------------------------------
123	  // The route owns the FormData side: validate the file and store its raw bytes;
124	  // `DraftEditor.applyImageUpload` then rewrites the targeted `…key` field on the
125	  // draft so the new image survives a reload and a later publish.
126	  const uploadTarget = imageUploadTarget(intent);
127	  if (uploadTarget !== null) {
128	    const file = form.get('file');
129	    if (!(file instanceof File) || file.size === 0) {
130	      return Response.json(
131	        { ok: false, error: 'Choose an image before uploading.', issues: [] },
132	        { status: 400 },
133	      );
134	    }
135	    if (!isAcceptedImageType(file.type)) {
136	      return Response.json(
137	        {
138	          ok: false,
139	          error: 'Upload a JPEG, PNG, WebP, GIF, or AVIF image.',
140	          issues: [],
141	        },
142	        { status: 400 },
143	      );
144	    }
145	
146	    const now = yield* Clock.currentTimeMillis;
147	    const key = uploadedImageKey(uploadTarget, file.type, now);
148	    const bytes = new Uint8Array(yield* Effect.promise(() => file.arrayBuffer()));
149	
150	    const putExit = yield* Effect.exit(storage.put(key, bytes, file.type));
151	    if (putExit._tag === 'Failure') {
152	      return Response.json(
153	        {
154	          ok: false,
155	          error:
156	            'Image upload failed — is the bucket configured? ' +
157	            Cause.pretty(putExit.cause),
158	          issues: [],
159	        },
160	        { status: 502 },
161	      );
162	    }
163	
164	    const applied = yield* editor
165	      .applyImageUpload(siteScope, uploadTarget, key)
166	      .pipe(Effect.result);
167	    if (applied._tag === 'Failure') return issueResponse(applied.failure);
168	    return redirect(
169	      `/admin/content?status=${encodeURIComponent(`Image uploaded: ${key}`)}`,
170	    );
171	  }
172	
173	  // ---- list op (add / remove / reorder) ------------------------------------
174	  // A per-list Add / Remove / reorder control submits `list:<path>:<kind>` fields
175	  // (ADR 0006). The route parses them into `ListOp`s; `DraftEditor.applyListOps`
176	  // performs the id-keyed structural edit on the draft and auto-saves it (settled
177	  // #10) so a freshly-added item's id exists server-side before a photo upload /
178	  // field edit targets it. An "Add" appends an item carrying only its id — draft-
179	  // valid, publish-invalid until its bilingual fields are filled (ADR 0006).
180	  if (intent === 'list-op') {
181	    const ops = collectListOps(form.entries());
182	    if (ops.length === 0) {
183	      return Response.json(
184	        { ok: false, error: 'No list change to apply.', issues: [] },
185	        { status: 400 },
186	      );
187	    }
188	    const applied = yield* editor.applyListOps(siteScope, ops).pipe(Effect.result);
189	    if (applied._tag === 'Failure') return issueResponse(applied.failure);
190	    return redirect('/admin/content?status=List%20updated.');
191	  }
192	
193	  if (intent !== 'save-draft' && intent !== 'publish') {
194	    return Response.json(
195	      { ok: false, error: 'Unknown submit intent.', issues: [] },
196	      { status: 400 },
197	    );
198	  }
199	
200	  // ---- save / publish ------------------------------------------------------
201	  // Parse the form into ONE override: dotted-path fields via `assembleOverrides`,
202	  // plus the `t:<locale>:<key>` translation fields folded onto `translations`
203	  // (their keys carry dots, so they can't ride the dotted-path convention).
204	  // `DraftEditor.editDocument` merges it onto the current document, decodes at
205	  // the single boundary, and stores the draft.
206	  const override = deepMerge(assembleOverrides(form.entries()), {
207	    translations: collectTranslations(form.entries()),
208	  } as Json);
209	
210	  const edited = yield* editor
211	    .editDocument(siteScope, override)
212	    .pipe(Effect.result);
213	  if (edited._tag === 'Failure') return issueResponse(edited.failure);
214	
215	  if (intent === 'save-draft') {
216	    return redirect('/admin/content?status=Draft%20saved.');
217	  }
218	
219	  // publish: promote the just-saved draft to the live document, drop the draft,
220	  // and bust the read cache so the change is live on the next public read.
221	  const published = yield* editor.publish(siteScope).pipe(Effect.result);
222	  if (published._tag === 'Failure') return issueResponse(published.failure);
223	  return redirect(
224	    '/admin/content?status=Published.%20Live%20on%20the%20next%20page%20load.',
225	  );
226	});
