380	function ListOpButton({
381	  listPath,
382	  kind,
383	  value,
384	  label,
385	  variant = 'default',
386	  disabled = false,
387	}: {
388	  readonly listPath: string;
389	  readonly kind: 'add' | 'remove' | 'reorder';
390	  readonly value: string;
391	  readonly label: string;
392	  readonly variant?: 'default' | 'add' | 'danger';
393	  readonly disabled?: boolean;
394	}) {
395	  const fetcher = useFetcher<ActionResult>();
396	  const pending = fetcher.state !== 'idle';
397	  const className =
398	    variant === 'add'
399	      ? 'inline-flex min-h-9 cursor-pointer items-center rounded-md border border-emerald-300 bg-emerald-50 px-3 text-xs font-medium text-emerald-800 hover:bg-emerald-100 disabled:opacity-50'
400	      : variant === 'danger'
401	        ? 'inline-flex min-h-9 cursor-pointer items-center rounded-md border border-rose-300 px-3 text-xs font-medium text-rose-700 hover:bg-rose-50 disabled:opacity-50'
402	        : 'inline-flex min-h-9 cursor-pointer items-center rounded-md border border-neutral-300 px-2 text-xs font-medium hover:bg-neutral-100 disabled:opacity-50';
403	
404	  const submit = () => {
405	    const data = new FormData();
406	    data.set('intent', 'list-op');
407	    data.set(listOpFieldName(listPath, kind), value);
408	    void fetcher.submit(data, { method: 'post' });
409	  };
410	
411	  return (
412	    <button
413	      type="button"
414	      onClick={submit}
415	      disabled={disabled || pending}
416	      className={className}
417	    >
418	      {pending ? '…' : label}
