423	/**
424	 * The per-item structural controls (ADR 0006): move up / down (a reorder
425	 * submitting the full new id order so a partial/stale order never drops an item)
426	 * and remove. Rendered next to each list item; the `ids` is the list's current
427	 * id order so a move computes the swapped permutation client-side.
428	 */
429	function ItemControls({
430	  listPath,
431	  ids,
432	  index,
433	}: {
434	  readonly listPath: string;
435	  readonly ids: readonly string[];
436	  readonly index: number;
437	}) {
438	  const id = ids[index];
439	  if (id === undefined) return null;
440	  // Swap two positions to compute the reorder permutation, guarding the bounds
441	  // so the disabled edge buttons (first item's "↑", last item's "↓") never
442	  // index past the array; out of range, the order is returned unchanged.
443	  const swapped = (a: number, b: number): string => {
444	    const aId = ids[a];
445	    const bId = ids[b];
446	    if (aId === undefined || bId === undefined) return ids.join(',');
447	    const next = [...ids];
448	    next[a] = bId;
449	    next[b] = aId;
450	    return next.join(',');
451	  };
452	  return (
453	    <div className="flex items-center gap-1">
454	      <ListOpButton
455	        listPath={listPath}
456	        kind="reorder"
457	        value={index > 0 ? swapped(index, index - 1) : ids.join(',')}
458	        label="↑"
459	        disabled={index === 0}
460	      />
461	      <ListOpButton
462	        listPath={listPath}
463	        kind="reorder"
464	        value={index < ids.length - 1 ? swapped(index, index + 1) : ids.join(',')}
465	        label="↓"
466	        disabled={index === ids.length - 1}
467	      />
468	      <ListOpButton
469	        listPath={listPath}
470	        kind="remove"
471	        value={id}
472	        label="Remove"
473	        variant="danger"
474	      />
475	    </div>
476	  );
477	}
