  2	 * Id-keyed list editing (ADR 0006, registration-launch Branch 2 sub-commit 2.2).
  3	 *
  4	 * The `/admin` editor used to grow/shrink lists by **array position** — it never
  5	 * could, in fact: the index-aligned `deepMerge` (`admin-form.ts`) can only
  6	 * overlay *existing* indices, so "add a speaker" / "remove a team member" was the
  7	 * CMS's headline gap (ADR 0006 Context). Now every list item carries a stable
  8	 * `id: ListItemId` (sub-commit 2.1), and structural edits address items **by
  9	 * id**, never by position.
 10	 *
 11	 * `applyListEdit` is the one deep operation: given the encoded document and a
 12	 * sequence of `ListOp`s, it navigates to each target list by its dotted path and
 13	 * applies an id-keyed add / remove / reorder. Identity — not position — is the
 14	 * key (`make-impossible-states-unrepresentable`): an id absent from a list is
 15	 * appended, an id present but not named survives, and a reorder is an explicit
 16	 * permutation of the surviving ids. The function is pure: it clones once and
 17	 * never mutates its input (`boundary-discipline`).
 18	 *
 19	 * The op-constructor sugar (`addOp`/`removeOp`/`reorderOp`), the control-field
 20	 * parser (`collectListOps`), and the id-keyed form field-name template
 21	 * (`fieldName`) are thin helpers around that one capability — they are NOT the
 22	 * interface's depth; `applyListEdit` is (`small-interface-deep-implementation`).
 23	 */
 24	
 25	import type { Json } from './admin-form';
 26	import type { ListItemId } from './schema';
 27	
 28	const isPlainObject = (value: Json): value is { readonly [k: string]: Json } =>
 29	  typeof value === 'object' && value !== null && !Array.isArray(value);
 30	
 31	/**
 32	 * A dotted path to a list (array) inside the encoded document — e.g. `team`, or
 33	 * `conferences.0.speakers`. Numeric segments index into an array (the document's
 34	 * `conferences`), string segments key into an object. The path addresses the
 35	 * **array**, not an item; the item is addressed by its `id` inside the `ListOp`.
 36	 */
 37	export type ListPath = string;
 38	
 39	/**
 40	 * A single structural list edit, addressed by item id (ADR 0006). Exactly one of
 41	 * add / remove / reorder per op so an op can never be two things at once
 42	 * (`make-impossible-states-unrepresentable`):
 43	 *   - `add`    — append a fresh item `{ id }` (empty otherwise) to the list. Its
 44	 *                required fields are absent, so it is publish-invalid until edited
 45	 *                (ADR 0006 consequence) — the id exists server-side so a later
 46	 *                photo upload / field edit has a target.
 47	 *   - `remove` — drop the item whose `id` matches; a no-op if absent.
 48	 *   - `reorder`— reorder the list to the given `ids` permutation; ids not present
 49	 *                are ignored and present-but-unnamed ids keep their relative order
 50	 *                after the named ones (so a partial order never drops an item).
 51	 */
 52	export type ListOp =
 53	  | { readonly add: { readonly listPath: ListPath; readonly id: ListItemId } }
 54	  | { readonly remove: { readonly listPath: ListPath; readonly id: ListItemId } }
 55	  | {
 56	      readonly reorder: {
 57	        readonly listPath: ListPath;
 58	        readonly ids: readonly ListItemId[];
 59	      };
 60	    };
 61	
 62	export const addOp = (listPath: ListPath, id: ListItemId): ListOp => ({
 63	  add: { listPath, id },
 64	});
 65	
 66	export const removeOp = (listPath: ListPath, id: ListItemId): ListOp => ({
 67	  remove: { listPath, id },
 68	});
 69	
 70	export const reorderOp = (
 71	  listPath: ListPath,
 72	  ids: readonly ListItemId[],
 73	): ListOp => ({ reorder: { listPath, ids } });
 74	
 75	/** The `id` of a list item, or `undefined` when the item is not an id-bearing object. */
 76	const itemId = (item: Json): string | undefined =>
 77	  isPlainObject(item) && typeof item['id'] === 'string' ? item['id'] : undefined;
 78	
 79	/**
 80	 * Apply one op to the array `list`, returning a fresh array (never mutating). The
 81	 * op kinds are exhaustive over the `ListOp` union, so adding a kind without
 82	 * handling it is a type error (`make-impossible-states-unrepresentable`).
 83	 */
 84	const applyOp = (list: readonly Json[], op: ListOp): readonly Json[] => {
 85	  if ('add' in op) {
 86	    // Appending a duplicate id would make two items share an identity, which the
 87	    // id-keyed merge could no longer distinguish — guard it (the caller mints a
 88	    // fresh id, so this only fires on a malformed resubmission).
 89	    if (list.some((item) => itemId(item) === op.add.id)) return list;
 90	    return [...list, { id: op.add.id }];
 91	  }
 92	  if ('remove' in op) {
 93	    return list.filter((item) => itemId(item) !== op.remove.id);
 94	  }
 95	  // reorder: place the named ids first in their given order, then append any
 96	  // surviving item the order omitted (in its original relative order) so a
 97	  // partial / stale order can never silently drop an item.
 98	  const named = new Map(
 99	    list.flatMap((item) => {
100	      const id = itemId(item);
101	      return id === undefined ? [] : ([[id, item]] as const);
102	    }),
103	  );
104	  const ordered: Json[] = [];
105	  const placed = new Set<string>();
106	  for (const id of op.reorder.ids) {
107	    const item = named.get(id);
108	    if (item !== undefined && !placed.has(id)) {
109	      ordered.push(item);
110	      placed.add(id);
111	    }
112	  }
113	  for (const item of list) {
114	    const id = itemId(item);
115	    if (id === undefined || !placed.has(id)) ordered.push(item);
116	  }
117	  return ordered;
118	};
