120	/**
121	 * Navigate to the array at `path` inside `root`, replace it via `update`, and
122	 * return a fresh document. Intermediate containers are cloned along the path so
123	 * the input is never mutated; a path that does not resolve to an array is left
124	 * untouched (the caller's listPath always names a real list, but a malformed
125	 * control field must not throw — the strict decode downstream is the gate).
126	 */
127	const updateListAtPath = (
128	  root: Json,
129	  path: readonly string[],
130	  update: (list: readonly Json[]) => readonly Json[],
131	): Json => {
132	  const [head, ...rest] = path;
133	  if (head === undefined) {
134	    return Array.isArray(root) ? update(root) : root;
135	  }
136	  if (Array.isArray(root)) {
137	    const index = Number(head);
138	    if (!Number.isInteger(index) || index < 0 || index >= root.length) {
139	      return root;
140	    }
141	    const next = [...root];
142	    next[index] = updateListAtPath(root[index] as Json, rest, update);
143	    return next;
144	  }
145	  if (isPlainObject(root)) {
146	    if (!(head in root)) return root;
147	    return { ...root, [head]: updateListAtPath(root[head] as Json, rest, update) };
148	  }
149	  return root;
150	};
151	
152	/**
153	 * Apply a sequence of id-keyed list ops to the encoded document, returning a new
154	 * document (the input is never mutated — `boundary-discipline`). Ops apply in
155	 * order, so a reorder naming a just-added id sees it. A `listPath` that does not
156	 * resolve to an array is skipped; the merged result is Schema-decoded downstream,
157	 * the single boundary where an invalid edit (an empty appended item on publish)
158	 * is rejected.
159	 */
160	export const applyListEdit = (base: Json, ops: readonly ListOp[]): Json =>
161	  ops.reduce((doc, op) => {
162	    const listPath =
163	      'add' in op
164	        ? op.add.listPath
165	        : 'remove' in op
166	          ? op.remove.listPath
167	          : op.reorder.listPath;
168	    return updateListAtPath(doc, listPath.split('.'), (list) => applyOp(list, op));
169	  }, base);
