175	/**
176	 * The form field-name prefix marking a list-op control field. The view's per-list
177	 * Add / Remove / reorder controls submit `list:<listPath>:<kind>` so the action
178	 * can recover the ops with `collectListOps`. The prefix keeps these control
179	 * fields out of `assembleOverrides`' dotted-path namespace (which never starts
180	 * with `list:`), so the two parsers can read the same `FormData` without overlap.
181	 */
182	const LIST_OP_PREFIX = 'list:';
183	
184	export type ListOpKind = 'add' | 'remove' | 'reorder';
185	
186	export const listOpFieldName = (
187	  listPath: ListPath,
188	  kind: ListOpKind,
189	): string => `${LIST_OP_PREFIX}${listPath}:${kind}`;
190	
191	/**
192	 * Parse the `list:<listPath>:<kind>` control fields of a submitted form into the
193	 * ordered op list. `add`/`remove` carry the target id as the value; `reorder`
194	 * carries the surviving ids comma-joined. Ids are kept as raw strings here
195	 * (parsed from untrusted form input) and branded only where `applyListEdit`
196	 * threads them back into the document the decoder validates — this helper does
197	 * not invent a brand at a non-boundary (`boundary-discipline`). A control field
198	 * with an empty / malformed value is skipped rather than throwing.
199	 */
200	export const collectListOps = (
201	  entries: Iterable<readonly [string, FormDataEntryValue]>,
202	): readonly ListOp[] => {
203	  const ops: ListOp[] = [];
204	  for (const [name, value] of entries) {
205	    if (typeof value !== 'string' || !name.startsWith(LIST_OP_PREFIX)) continue;
206	    const rest = name.slice(LIST_OP_PREFIX.length);
207	    const sep = rest.lastIndexOf(':');
208	    if (sep === -1) continue;
209	    const listPath = rest.slice(0, sep);
210	    const kind = rest.slice(sep + 1);
211	    if (listPath === '') continue;
212	    if (kind === 'add') {
213	      if (value !== '') ops.push(addOp(listPath, value as ListItemId));
214	    } else if (kind === 'remove') {
215	      if (value !== '') ops.push(removeOp(listPath, value as ListItemId));
216	    } else if (kind === 'reorder') {
217	      const ids = value
218	        .split(',')
219	        .map((id) => id.trim())
220	        .filter((id) => id !== '') as ListItemId[];
221	      if (ids.length > 0) ops.push(reorderOp(listPath, ids));
222	    }
223	  }
224	  return ops;
225	};
