227	/**
228	 * The id-keyed form field-name for a leaf of a list item — e.g.
229	 * `fieldName('conferences.0.speakers', id, 'name.en')` →
230	 * `conferences.0.speakers.<id>.name.en`. This replaces the positional templates
231	 * (`conferences.0.speakers.1.name.en`) the index merge relied on (ADR 0006); the
232	 * id segment is a validated `ListItemId`, so it can never smuggle a `.`-bearing
233	 * path that would re-split into the wrong shape (`boundary-discipline`).
234	 */
235	export const fieldName = (
236	  listPath: ListPath,
237	  id: ListItemId,
238	  leaf: string,
239	): string => `${listPath}.${id}.${leaf}`;

