242	/**
243	 * Select the current conference from the decoded document, matching today's
244	 * `getCurrentConference` semantics exactly (CONTEXT.md §"Current Conference"):
245	 * the first conference whose start date is still in the future, falling back to
246	 * the most recent (last) one.
247	 */
248	const selectCurrent = (
249	  content: SiteContentType,
250	  locale: Locale,
251	  now: number,
252	): Conference => {
253	  const index = content.conferences.findIndex((conference) =>
254	    dayjs(now).isBefore(toEndOfDayMs(conference.dates.start)),
255	  );
256	  const conference =
257	    index === -1 ? content.conferences[content.conferences.length - 1] : content.conferences[index];
258	  if (conference === undefined) {
259	    throw new Error('No conferences are configured');
260	  }
261	  return toConference(conference, locale);
262	};
263	
264	const selectByYear = (
265	  content: SiteContentType,
266	  locale: Locale,
267	  year: number,
268	): Conference => {
269	  // A Conference is identified by its year `slug` (`/YYYY`, CONTEXT.md
270	  // §"Conference"), which is the canonical year identifier the routes pass and
271	  // the `SiteContent` boundary filter requires to be present. Match on it
272	  // directly rather than re-deriving the year from `dates.start`, so this
273	  // selector and the schema invariant agree (`derive-dont-sync`) and any
274	  // year the routes serve is guaranteed present by the time we get here.
275	  const conference = content.conferences.find(
276	    (candidate) => candidate.slug === `/${year}`,
277	  );
278	  if (conference === undefined) {
279	    throw new Error(`No conference found for year ${year}`);
280	  }
281	  return toConference(conference, locale);
282	};
