288	/** The bucket key the published `SiteContent` document lives at. */
289	export const SITE_CONTENT_KEY = 'content/site.json';
290	
291	/**
292	 * The bucket key the *unpublished* draft lives at. The `/admin` editor (C5)
293	 * writes here on "Save draft" and reads here first so an in-progress edit
294	 * survives a reload without going live; "Publish" promotes the draft to
295	 * `SITE_CONTENT_KEY` and removes it. The public read path
296	 * (`getSiteContent`) never reads the draft.
297	 */
298	export const SITE_CONTENT_DRAFT_KEY = 'content/site.draft.json';
299	
300	/** Where the editor's content originated, for the admin banner. */
301	export type AdminContentSource = 'draft' | 'published' | 'defaults';
302	
303	export interface AdminContent {
304	  /**
305	   * The document the `/admin` editor opens. It is the **draft** shape
306	   * (`DraftSiteContent`): a published / defaults source is also a valid draft (a
307	   * complete document trivially satisfies the laxer draft schema), while a
308	   * reopened draft may carry freshly-added list items that hold only their `id`
309	   * (ADR 0006, settled #10). Publish re-decodes the strict `SiteContent`, the
310	   * single boundary that enforces the both-locales `Text` invariant.
311	   */
312	  readonly content: DraftSiteContentType;
313	  readonly source: AdminContentSource;
314	}
