316	/**
317	 * Cache TTL. Short by design (D3 — runtime read with cache, no redeploy): a
318	 * publish becomes visible on the next read after the TTL elapses (or the
319	 * editor's explicit `bust`). 30s keeps the bucket-read rate negligible while
320	 * making edits feel near-instant.
321	 */
322	const CACHE_TTL_MS = 30_000;
323	
324	/**
325	 * Parse a `content/site.json` string and decode it to a `SiteContent`, running
326	 * the id-backfill normalization between parse and decode so a document
327	 * published before list-item ids existed (ADR 0006) still decodes — every id-less
328	 * list item gets a fresh `nanoid` before the required `id` field is checked. The
329	 * two-step (parse → backfill → decode), rather than a single `fromJsonString`,
330	 * is what lets the normalization see the parsed value before validation.
331	 */
332	const parseJson = Schema.decodeUnknownEffect(
333	  Schema.fromJsonString(Schema.Unknown),
334	);
335	const decodeSiteContent = Schema.decodeUnknownEffect(SiteContent);
336	const decodeDocument = (json: string) =>
337	  parseJson(json).pipe(
338	    Effect.map(backfillListItemIds),
339	    Effect.flatMap(decodeSiteContent),
340	  );

  1	/**
  2	 * Pure helpers for the `/admin` content editor (CMS plan sub-commit C5).
  3	 *
  4	 * The editor edits the one `SiteContent` document. Rather than rebuild the whole
  5	 * (deeply nested, array-bearing) document from scratch on every save — which
  6	 * would make a single typo in one field able to drop an entire speaker bio — the
  7	 * editor takes the **merge-onto-current-document** approach
  8	 * (`make-impossible-states-unrepresentable`, no-bail-outs):
  9	 *
 10	 *   1. the form carries only the fields it renders, named by their dotted JSON
 11	 *      path (`conferences.2.themeName.en`, `team.0.name`, `translations.fr.…`);
 12	 *   2. `assembleOverrides` parses those into a nested partial object;
 13	 *   3. `deepMerge` overlays that partial onto the *encoded current document*, so
 14	 *      every unedited field (long bios, image keys, `Option` registration
 15	 *      windows omitted from the encoded JSON) survives verbatim;
 16	 *   4. the route then Schema-decodes the merged result — the single boundary
 17	 *      where an edit can be rejected (`boundary-discipline`).
 18	 *
 19	 * Keeping this logic pure and separate from the route makes it unit-testable
 20	 * without a runtime (`small-interface-deep-implementation`).
 21	 */
 22	
 23	import { AssetKey } from './schema';
 24	
 25	/**
 26	 * A JSON-shaped value the merge/assemble helpers move around. Arrays / objects
 27	 * are `readonly` so an encoded Effect-Schema value (whose fields are deeply
 28	 * `readonly`) is assignable without a cast; the helpers never mutate their
 29	 * inputs (they build fresh values / clone).
 30	 */
 31	export type Json =
 32	  | string
 33	  | number
 34	  | boolean
 35	  | null
 36	  | readonly Json[]
 37	  | { readonly [key: string]: Json };
 38	
 39	type MutableJsonObject = Record<string, Json>;
 40	
 41	const isPlainObject = (value: Json): value is { readonly [k: string]: Json } =>
 42	  typeof value === 'object' && value !== null && !Array.isArray(value);
 43	
 44	/**
 45	 * The form field-name prefix that marks an image-upload submit. The editor's
 46	 * per-image "Upload" buttons submit `intent=upload:<dotted-key-path>` so the
 47	 * action knows which `…photo.key` / `hero.<crop>.key.<locale>` field to rewrite
 48	 * with the new bucket key once the bytes are stored.
 49	 */
 50	export const IMAGE_UPLOAD_INTENT_PREFIX = 'upload:';
 51	
 52	/**
 53	 * The accepted upload content-types. The resize/WebP pipeline is deferred (CMS
 54	 * plan §"Non-goals"); for now we store the raw bytes under their original
 55	 * content-type, so we only need to gate the obviously-image MIME types to keep
 56	 * a stray PDF / script out of the image namespace.
 57	 */
 58	const ACCEPTED_IMAGE_TYPES = new Set([
 59	  'image/jpeg',
 60	  'image/png',
 61	  'image/webp',
 62	  'image/gif',
 63	  'image/avif',
 64	]);
 65	
 66	export const isAcceptedImageType = (type: string): boolean =>
 67	  ACCEPTED_IMAGE_TYPES.has(type.toLowerCase());
 68	
 69	const EXTENSION_BY_TYPE: Record<string, string> = {
 70	  'image/jpeg': 'jpg',
 71	  'image/png': 'png',
 72	  'image/webp': 'webp',
 73	  'image/gif': 'gif',
 74	  'image/avif': 'avif',
 75	};
 76	
 77	export const extensionForType = (type: string): string =>
 78	  EXTENSION_BY_TYPE[type.toLowerCase()] ?? 'bin';
 79	
 80	/**
 81	 * Recover the dotted key path an image-upload intent targets, or `null` if the
 82	 * intent is not an upload. E.g. `upload:conferences.0.speakers.1.photo.key` →
 83	 * `conferences.0.speakers.1.photo.key`.
 84	 */
 85	export const imageUploadTarget = (intent: string): string | null => {
 86	  if (!intent.startsWith(IMAGE_UPLOAD_INTENT_PREFIX)) return null;
 87	  const path = intent.slice(IMAGE_UPLOAD_INTENT_PREFIX.length);
 88	  return path.length > 0 ? path : null;
 89	};
 90	
 91	/**
 92	 * Build a fresh bucket object key for an uploaded image, namespaced under
 93	 * `images/` so it never collides with the bundled `public/<year>/…` art and is
 94	 * obviously an editor upload. `seed` (a millisecond timestamp) keeps successive
 95	 * uploads to the same field distinct so a stale cached image is never served
 96	 * for a new upload (`make-operations-idempotent` — each upload is its own key).
 97	 *
 98	 * Returns a branded `AssetKey`, not a raw `string`: the construction
 99	 * (`images/uploads/` namespace + a `[a-zA-Z0-9-]` slug) is valid by
100	 * construction, and `AssetKey.make` *validates* that invariant at the producer
101	 * boundary (`boundary-discipline`, `make-impossible-states-unrepresentable`) so
102	 * a non-`AssetKey` can never reach `DraftEditor.applyImageUpload`. A failure
103	 * here would be a slug-construction bug, surfaced as a throw — not a silent
104	 * widening.
105	 */
106	export const uploadedImageKey = (
107	  targetPath: string,
108	  contentType: string,
109	  seed: number,
110	): AssetKey => {
111	  const slug = targetPath.replace(/[^a-zA-Z0-9]+/g, '-').replace(/^-+|-+$/g, '');
112	  return AssetKey.make(
113	    `images/uploads/${slug}-${seed}.${extensionForType(contentType)}`,
114	  );
115	};
