117	/**
118	 * The form-name prefix for a single translation value. Translation keys contain
119	 * dots (`main.newsletter.title`), which collide with the dotted-path convention,
120	 * so translation inputs are named `TRANSLATION_FIELD_PREFIX<locale>:<key>` and
121	 * collected by `collectTranslations` rather than parsed by `assembleOverrides`
122	 * (which skips them). The key is kept whole — never split on its dots.
123	 */
124	export const TRANSLATION_FIELD_PREFIX = 't:';
125	
126	export const translationFieldName = (locale: 'en' | 'fr', key: string): string =>
127	  `${TRANSLATION_FIELD_PREFIX}${locale}:${key}`;
128	
129	const isTranslationField = (name: string): boolean =>
130	  name.startsWith(TRANSLATION_FIELD_PREFIX);
131	
132	/**
133	 * Collect every `t:<locale>:<key>` form field into the bilingual translations
134	 * override, e.g. `t:en:main.newsletter.title` → `{ en: { 'main.newsletter.title':
135	 * '…' } }`. The key keeps its dots verbatim (it is a single map key, not a path).
136	 */
137	export const collectTranslations = (
138	  entries: Iterable<readonly [string, FormDataEntryValue]>,
139	): { readonly en: Record<string, string>; readonly fr: Record<string, string> } => {
140	  const en: Record<string, string> = {};
141	  const fr: Record<string, string> = {};
142	  for (const [name, value] of entries) {
143	    if (typeof value !== 'string' || !isTranslationField(name)) continue;
144	    const rest = name.slice(TRANSLATION_FIELD_PREFIX.length);
145	    const sep = rest.indexOf(':');
146	    if (sep === -1) continue;
147	    const locale = rest.slice(0, sep);
148	    const key = rest.slice(sep + 1);
149	    if (key === '') continue;
150	    if (locale === 'en') en[key] = value;
151	    else if (locale === 'fr') fr[key] = value;
152	  }
153	  return { en, fr };
154	};
155	
156	const isIndex = (segment: string): boolean => /^\d+$/.test(segment);
157	
158	/**
159	 * Set `value` at the dotted `path` inside `root`, creating intermediate objects
160	 * (or arrays, when the next segment is numeric) as needed. Mirrors the
161	 * paulo-suzanne admin's `setPath` but typed to `Json`.
162	 */
163	const setPath = (root: MutableJsonObject, path: string[], value: Json): void => {
164	  if (path.length === 0) return;
165	  let cursor: MutableJsonObject | Json[] = root;
166	  for (let i = 0; i < path.length - 1; i += 1) {
167	    const segment = path[i];
168	    const next = path[i + 1];
169	    if (segment === undefined || next === undefined) return;
170	    const key = Array.isArray(cursor) ? Number(segment) : segment;
171	    const existing = (cursor as MutableJsonObject)[key as keyof typeof cursor];
172	    if (isPlainObject(existing as Json) || Array.isArray(existing)) {
173	      cursor = existing as MutableJsonObject | Json[];
174	    } else {
175	      const container: MutableJsonObject | Json[] = isIndex(next) ? [] : {};
176	      (cursor as MutableJsonObject)[String(key)] = container;
177	      cursor = container;
178	    }
179	  }
180	  const leaf = path[path.length - 1];
181	  if (leaf === undefined) return;
182	  if (Array.isArray(cursor) && isIndex(leaf)) {
183	    cursor[Number(leaf)] = value;
184	  } else {
185	    (cursor as MutableJsonObject)[leaf] = value;
186	  }
187	};
188	
189	/**
190	 * Assemble the nested override object from the editor form. Only entries whose
191	 * name is a dotted path are taken; control fields (`intent`, anything starting
192	 * with `_`) and non-string values (files) are skipped. A leaf named `chapter` /
193	 * `verse` is coerced to a number so the `BibleRef` integer fields decode.
194	 */
195	export const assembleOverrides = (
196	  entries: Iterable<readonly [string, FormDataEntryValue]>,
197	): Json => {
198	  const root: MutableJsonObject = {};
199	  for (const [name, value] of entries) {
200	    if (typeof value !== 'string') continue;
201	    if (name === 'intent' || name.startsWith('_')) continue;
202	    if (isTranslationField(name)) continue;
203	    const path = name.split('.');
204	    const leaf = path[path.length - 1];
205	    const coerced: Json =
206	      (leaf === 'chapter' || leaf === 'verse') && value.trim() !== ''
207	        ? Number(value)
208	        : value;
209	    setPath(root, path, coerced);
210	  }
211	  return root;
212	};
213	
214	/**
215	 * Deep-merge `overrides` onto `base`, returning a new value. Objects merge
216	 * key-by-key; arrays merge element-by-element by index (so editing
217	 * `conferences.0.themeName.en` overlays only that leaf and leaves
218	 * `conferences.0.speakers` untouched); every other value (string / number /
219	 * boolean / null) is replaced. `base` and `overrides` are never mutated.
220	 */
221	export const deepMerge = (base: Json, overrides: Json): Json => {
222	  if (isPlainObject(base) && isPlainObject(overrides)) {
223	    const result: MutableJsonObject = { ...base };
224	    for (const key of Object.keys(overrides)) {
225	      const next = overrides[key];
226	      result[key] =
227	        key in base && next !== undefined
228	          ? deepMerge(base[key] as Json, next)
229	          : (next as Json);
230	    }
231	    return result;
232	  }
233	  if (Array.isArray(base) && Array.isArray(overrides)) {
234	    const result: Json[] = [...base];
235	    for (let i = 0; i < overrides.length; i += 1) {
236	      const next = overrides[i];
237	      if (next === undefined) continue;
238	      result[i] = i < base.length ? deepMerge(base[i] as Json, next) : next;
239	    }
240	    return result;
241	  }
242	  return overrides;
243	};
244	
245	/** Set the leaf at a dotted `path` on a structurally-cloned copy of `doc`. */
246	export const setAtPath = (doc: Json, path: string, value: Json): Json => {
247	  const clone = structuredClone(doc) as MutableJsonObject;
248	  setPath(clone, path.split('.'), value);
249	  return clone;
250	};

